class ModuleNameTaint extends TaintTracking::Configuration {
  override predicate isSource(DataFlow::Node n) {
    n.asExpr() instanceof getModuleNameCall
  }
  override predicate isSink(DataFlow::Node n) {
    // argument to Set.contains() that is the security check
    exists(MethodAccess ma |
      ma.getMethod().hasQualifiedName("java.util", "Set", "contains")
      and n.asExpr() = ma.getArgument(0))
  }
}
